"""Claude Code harness adapter (vNext §12.2 Claude)."""

from __future__ import annotations

import json
from pathlib import Path

from zeref.adapters.harnesses.base import (
    HarnessEnforcementLevel,
    HarnessReport,
    env_hint,
    which,
)

BANNER = (
    "<!-- GENERATED BY ZEREF. SOURCE: memory/state/zeref2.sqlite. "
    "DO NOT EDIT DIRECTLY. -->\n"
)


class ClaudeCodeAdapter:
    name = "claude-code"

    def detect(self) -> HarnessReport:
        version = env_hint("CLAUDE_CODE_VERSION", "CLAUDECODE_VERSION")
        binary = which("claude") or which("claude-code")
        home = Path.home() / ".claude"
        detected = bool(version) or bool(binary) or home.exists()
        if not version and home.exists():
            version = "home-dir-present"
        return HarnessReport(
            name=self.name,
            detected=detected,
            detected_version=version,
            enforcement_level=(HarnessEnforcementLevel.embedded if detected
                               else HarnessEnforcementLevel.context_only),
            supported_features=("CLAUDE.md", "hooks", "subagents", "MCP",
                                 "slash_commands", "skills",
                                 "structured_output", "session_export"),
            instruction_files=("CLAUDE.md",),
            failure_reason=None if detected else "no claude binary, env var, or ~/.claude/",
        )

    def health(self) -> HarnessReport:
        return self.detect()

    def export_context(self, root: Path, *, objective: str,
                        permissions: dict) -> list[Path]:
        target = root / "CLAUDE.md"
        target.write_text(
            BANNER
            + f"# Objective\n\n{objective}\n\n"
            + "# Permission Contract\n\n```json\n"
            + json.dumps(permissions, indent=2, sort_keys=True)
            + "\n```\n",
            encoding="utf-8",
        )
        return [target]
